Refactored for clarity and correctness. The cache is kept consistent with the
database: updates to a product update the cached value as well. get_product
returns a shallow copy of the product dict to prevent callers from mutating
internal state.
"""

from typing import Any, Dict, Optional


class ProductCatalog:
    """A simple in-memory product catalog with a read cache.

    - _db stores the authoritative product data.
    - _cache stores copies of recently-read products for faster repeated lookups.

    All public methods return copies (where appropriate) so callers cannot
    accidentally mutate internal state.
    """

    def __init__(self) -> None:
        self._db: Dict[Any, Dict[str, Any]] = {}
        self._cache: Dict[Any, Dict[str, Any]] = {}

    def add_product(self, product_id: Any, name: str, price: float) -> None:
        """Add a product to the database and update the cache.

        If the product already exists it will be overwritten with the new
        values. The cache is updated to keep it consistent with the DB.
        """
        self._db[product_id] = {"name": name, "price": price}
        # Store a copy in the cache so callers get isolated dicts
        self._cache[product_id] = dict(self._db[product_id])

    def get_product(self, product_id: Any) -> Optional[Dict[str, Any]]:
        """Return a copy of the product data for product_id, or None if missing.

        Uses a small read cache to speed up repeated lookups. Always returns a
        shallow copy so callers cannot mutate the internal cache or DB.
        """
        if product_id in self._cache:
            return dict(self._cache[product_id])

        product = self._db.get(product_id)
        if product is None:
            return None

        # Cache a copy and return a copy to the caller
        self._cache[product_id] = dict(product)
        return dict(self._cache[product_id])

    def update_product(self, product_id: Any, **fields: Any) -> bool:
        """Update product fields in the database and keep the cache consistent.

        Returns True if the product existed and was updated, False otherwise.
        After a successful update the cache is replaced with a fresh copy of
        the database value so get_product() always returns current data.
        """
        if product_id not in self._db:
            return False

        self._db[product_id].update(fields)
        # Replace the cached value with an up-to-date copy to avoid stale reads
        self._cache[product_id] = dict(self._db[product_id])
        return True

    def reset(self) -> None:
        """Clear the database and cache."""
        self._db.clear()
        self._cache.clear()


# Module-level singleton to preserve the original API
