from worker import process, batch_process


_shared_log = []


def with_history(func=None, history=None):
    """Decorator that records call history for a function.

    Usage:
    - @with_history
    - @with_history(history=some_list)

    Invariant: each decorated function gets its OWN independent history list
    unless an explicit history list is provided.
    """
    # Support both @with_history and @with_history(history=...)
    if func is None:
        return lambda f: with_history(f, history=history)

    if history is None:
        # Create a fresh list for this decorator instance to avoid sharing
        history = []

    def wrapper(*args, **kwargs):
        result = func(*args, **kwargs)
        history.append({"func": func.__name__, "args_count": len(args)})
        return result

    wrapper.get_history = lambda: list(history)
    wrapper.clear_history = lambda: history.clear()
    return wrapper


