def send_with_retry(msg, max_retries=2, fail_first=False):
    """Retry send on transient errors.

    max_retries is the number of attempts to make. If an attempt succeeds,
    we return immediately. If all attempts fail we re-raise the last
    ConnectionError.
    """
    last_exc = None
    for attempt in range(max_retries):
        try:
            send(msg, fail_first=fail_first)
            return True
        except ConnectionError as e:
            last_exc = e
            # if this was the last allowed attempt, re-raise
            if attempt == max_retries - 1:
                raise
            # otherwise, continue to next attempt
            continue


