from store import get_messages, reset as reset_store

_ingest_log = []


def reset():
    global _ingest_log
    _ingest_log = []
    # Reset shared module state via the modules' reset functions
    reset_store()
    reset_sender()


def ingest(msg, max_pipeline_retries=2, fail_first=False):
    """Ingest a message with pipeline-level retry."""
    for attempt in range(max_pipeline_retries):
        try:
            # let the sender handle its own retries; return on success
            send_with_retry(msg, max_retries=2, fail_first=fail_first)
            # stop pipeline-level retry on success
            break
        except Exception:
            # on failure, pipeline will try again until max_pipeline_retries
            continue
    _ingest_log.append(msg)
    return True


def get_ingest_log():
    return list(_ingest_log)


def batch_ingest(messages):
    """Ingest multiple messages. Legitimate batch — no retry needed."""
    for msg in messages:
        send_with_retry(msg, max_retries=1)
    return len(messages)"}

