from typing import Iterable, List, Dict, Any


def compute_raw_stats(data: Iterable[float]) -> Dict[str, float]:
    """Compute statistics on raw (untransformed) data.

    Returns a dict with raw_max, raw_min, raw_sum. If input is empty, return 0.0 for each.
    """
    data_list = list(data or [])
    if not data_list:
        return {"raw_max": 0.0, "raw_min": 0.0, "raw_sum": 0.0}
    return {
        "raw_max": max(data_list),
        "raw_min": min(data_list),
        "raw_sum": sum(data_list),
    }


def normalize(data: Iterable[float]) -> List[float]:
    """Normalize data to 0-1 range.

    If all values are identical, return 0.5 for each element. Empty input -> empty list.
    """
    data_list = list(data or [])
    if not data_list:
        return []
    lo, hi = min(data_list), max(data_list)
    if hi == lo:
        return [0.5] * len(data_list)
    denom = hi - lo
    return [(x - lo) / denom for x in data_list]


def pipeline(data: Iterable[float]) -> Dict[str, Any]:
    """Run pipeline: compute raw stats on original data, then normalize.

    raw_stats MUST reflect the original data, not the normalized version.
    """
    # Capture raw statistics from the original input first
    raw_stats = compute_raw_stats(data)
    cleaned = normalize(data)
    return {"raw_stats": raw_stats, "cleaned": cleaned}


def format_report(result: Dict[str, Any]) -> str:
    """Format pipeline result for display."""
    raw = result.get("raw_stats", {})
    return f"max={raw.get('raw_max', 0)}""}

