from models import Account
from ledger import record_debit, record_credit, record_transfer_attempt
from audit import emit_transfer_event, emit_failure_alert


class TransferError(Exception):
    """Raised when a transient failure happens during transfer.

    Carries a 'progress' dict describing which steps completed (debited/credited).
    """

    def __init__(self, message, progress=None):
        super().__init__(message)
        self.progress = progress or {}


def validate_transfer(sender, amount):
    if amount <= 0:
        raise ValueError("amount must be positive")
    if sender.balance < amount:
        raise ValueError("insufficient funds")


def _transfer_core(sender, receiver, amount):
    """Core transfer logic without any observability side-effects.

    Returns a progress dict: {'debited': bool, 'credited': bool} on success.
    May raise TransferError(message, progress) if a transient failure occurs after some steps.
    """
    validate_transfer(sender, amount)

    progress = {"debited": False, "credited": False}

    # Debit phase (pure state change)
    sender.balance -= amount
